    WorshipItem(id: 'name_91', categoryId: 'allah_names', title: 'الْمَانِعُ', sortOrder: 89, repeatHint: '٩٠', body: 'الذي يمنع ما يشاء بحكمته، ويحفظ من يشاء.'),
    WorshipItem(id: 'name_92', categoryId: 'allah_names', title: 'الضَّارُّ', sortOrder: 90, repeatHint: '٩١', body: 'الذي يُقدّر الضر على من يشاء بحكمته.'),
    WorshipItem(id: 'name_93', categoryId: 'allah_names', title: 'النَّافِعُ', sortOrder: 91, repeatHint: '٩٢', body: 'الذي يُقدّر النفع لمن يشاء من عباده.'),
    WorshipItem(id: 'name_94', categoryId: 'allah_names', title: 'النُّورُ', sortOrder: 92, repeatHint: '٩٣', body: 'نور السماوات والأرض، يهدي به قلوب المؤمنين.'),
    WorshipItem(id: 'name_95', categoryId: 'allah_names', title: 'الْهَادِي', sortOrder: 93, repeatHint: '٩٤', body: 'الذي يهدي من يشاء إلى صراطه المستقيم.'),
    WorshipItem(id: 'name_96', categoryId: 'allah_names', title: 'الْبَدِيعُ', sortOrder: 94, repeatHint: '٩٥', body: 'الذي أبدع الخلق على غير مثال سبق.'),
    WorshipItem(id: 'name_97', categoryId: 'allah_names', title: 'الْبَاقِي', sortOrder: 95, repeatHint: '٩٦', body: 'الدائم الذي لا يزول ولا يفنى، يبقى بعد فناء خلقه.'),
    WorshipItem(id: 'name_98', categoryId: 'allah_names', title: 'الْوَارِثُ', sortOrder: 96, repeatHint: '٩٧', body: 'الباقي بعد فناء الخلق، يرث الأرض ومن عليها.'),
    WorshipItem(id: 'name_99', categoryId: 'allah_names', title: 'الرَّشِيدُ', sortOrder: 97, repeatHint: '٩٨', body: 'الذي أرشد خلقه إلى ما فيه صلاحهم، ولا يأمر إلا بالحكمة.'),
    WorshipItem(id: 'name_100', categoryId: 'allah_names', title: 'الصَّبُورُ', sortOrder: 98, repeatHint: '٩٩', body: 'الذي لا يعاجل العصاة بالعقوبة، ويُمهلهم للتوبة.'),
  ];
}
